const fs = require('fs');
function readLog(filePath){
    return new Promise((resolve, reject)=>{
      let error=false;
      let res = '';
      fs.readFile(filePath,'utf8', (err ,data) => {
        if(err)
          reject(error);
        else 
          resolve(res);
      });
    })
}
module.exports = readLog